   815→      if (whisperResult && whisperResult.text && whisperResult.text.trim().length > 20) {
   816→        finalTranscription = whisperResult.text;
   817→        console.log(`[ai] Whisper transcription: ${finalTranscription.length} chars (replaced browser transcription)`);
   818→      } else {
   819→        console.log('[ai] Whisper result too short, keeping browser transcription');
   820→      }
   821→    } catch (err) {
   822→      console.warn('[ai] Whisper failed, using browser transcription:', err.message);
   823→    }
   824→  }
   825→
   826→  // Step 2: Run all analyses in parallel — use allSettled so partial failures don't kill the whole pipeline
   827→  const analysisPromises = [
   828→    analyzeInterviewResponse(question, finalTranscription, keyPoints, options),
   829→    generateInterviewCoaching(question, finalTranscription, { score: 5, strengths: [], improvements: [] }, options),
   830→    analyzeVideoPresentation(frames, options)
   831→  ];
   832→
   833→  // Add voice quality analysis if we have audio
   834→  if (audioData) {
   835→    analysisPromises.push(analyzeVoiceQuality(finalTranscription, durationSeconds, options));
   836→  }
   837→
   838→  const settled = await Promise.allSettled(analysisPromises);
   839→
   840→  // Extract results with fallbacks for any failed analyses
   841→  const contentAnalysis = settled[0].status === 'fulfilled' ? settled[0].value : {
   842→    score: 5, strengths: ['Response provided'], improvements: ['AI analysis temporarily unavailable'],
