   846→    improved_response: '', specific_tips: ['Try again for detailed tips'], body_language_tips: [],
   847→    common_mistake: '', practice_prompt: ''
   848→  };
   849→  const videoAnalysis = settled[2].status === 'fulfilled' ? settled[2].value : {
   850→    eye_contact: { score: 5, feedback: 'Video analysis unavailable' },
   851→    facial_expressions: { score: 5, feedback: 'Video analysis unavailable' },
   852→    body_language: { score: 5, feedback: 'Video analysis unavailable' },
   853→    professional_appearance: { score: 5, feedback: 'Video analysis unavailable' },
   854→    overall_presentation: 5, summary: 'Video analysis temporarily unavailable.', timestamped_notes: []
   855→  };
   856→  const voiceAnalysis = (audioData && settled[3] && settled[3].status === 'fulfilled') ? settled[3].value : null;
   857→
   858→  // Log any failures for debugging
   859→  settled.forEach((s, i) => {
   860→    if (s.status === 'rejected') {
   861→      const names = ['contentAnalysis', 'contentCoaching', 'videoAnalysis', 'voiceAnalysis'];
   862→      console.error(`[video-analysis] ${names[i]} failed:`, s.reason?.message || s.reason);
   863→    }
   864→  });
   865→
   866→  // Algorithmic speech analysis
   867→  const speechAnalysis = analyzeSpeechPatterns(finalTranscription, durationSeconds);
   868→
   869→  // Calculate category scores
